#include <iostream>
#include <optional>
#include <string>

constexpr int MAX_ACCOUNTS{16};
constexpr int MAX_TXS{64};

struct Money { long long cents{0}; };

std::string format_money(const Money& m) {
    long long abs_c{m.cents < 0 ? -m.cents : m.cents};
    std::string sign{m.cents < 0 ? "-" : ""};
    std::string p{abs_c % 100 < 10 ? "0" + std::to_string(abs_c % 100) : std::to_string(abs_c % 100)};
    return sign + "$" + std::to_string(abs_c / 100) + "." + p;
}

enum class TxKind { Deposit, Withdrawal, TransferIn, TransferOut };

const char* tx_label(TxKind k) {
    switch (k) {
        case TxKind::Deposit:     return "deposit";
        case TxKind::Withdrawal:  return "withdrawal";
        case TxKind::TransferIn:  return "transfer-in";
        case TxKind::TransferOut: return "transfer-out";
    }
    return "?";
}

struct Transaction { TxKind kind{TxKind::Deposit}; Money amount{}; int other_id{0}; };

class Account {
public:
    Account() = default;
    Account(int id, const std::string& name) : m_id{id}, m_name{name} {}
    int id() const { return m_id; }
    const std::string& name() const { return m_name; }
    Money balance() const { return m_balance; }
    void deposit(Money amt, int other = 0, bool xfer = false) {
        m_balance.cents += amt.cents;
        record(xfer ? TxKind::TransferIn : TxKind::Deposit, amt, other);
    }
    bool withdraw(Money amt, int other = 0, bool xfer = false) {
        if (amt.cents > m_balance.cents) return false;
        m_balance.cents -= amt.cents;
        record(xfer ? TxKind::TransferOut : TxKind::Withdrawal, amt, other);
        return true;
    }
    int tx_count() const { return m_tx_count; }
    const Transaction& tx(int i) const { return m_txs[i]; }
private:
    void record(TxKind k, Money amt, int other) {
        if (m_tx_count < MAX_TXS) m_txs[m_tx_count++] = Transaction{k, amt, other};
    }
    int m_id{0};
    std::string m_name{};
    Money m_balance{};
    Transaction m_txs[MAX_TXS]{};
    int m_tx_count{0};
};

class Bank {
public:
    int open(const std::string& name) {
        if (m_count >= MAX_ACCOUNTS) return -1;
        int id{m_next_id++};
        m_accounts[m_count++] = Account{id, name};
        return id;
    }
    Account* find(int id) {
        for (int i{0}; i < m_count; ++i)
            if (m_accounts[i].id() == id) return &m_accounts[i];
        return nullptr;
    }
    std::optional<Money> total_assets() const {
        if (m_count == 0) return std::nullopt;
        Money sum{};
        for (int i{0}; i < m_count; ++i) sum.cents += m_accounts[i].balance().cents;
        return sum;
    }
    int count() const { return m_count; }
private:
    Account m_accounts[MAX_ACCOUNTS]{};
    int m_count{0};
    int m_next_id{1};
};

static Account* require(Bank& bank, int id) {
    Account* a{bank.find(id)};
    if (!a) std::cout << "Unknown account #" << id << "\n";
    return a;
}

int main() {
    Bank bank{};
    std::string cmd;
    while (std::cin >> cmd) {
        if (cmd == "open") {
            std::string name; std::cin >> name;
            int id{bank.open(name)};
            std::cout << "Opened #" << id << " " << name << "\n";
        } else if (cmd == "balance") {
            int id; std::cin >> id;
            if (Account* a{require(bank, id)})
                std::cout << "Account #" << a->id() << " " << a->name() << ": " << format_money(a->balance()) << "\n";
        } else if (cmd == "deposit") {
            int id; long long c; std::cin >> id >> c;
            Account* a{require(bank, id)};
            if (!a) continue;
            a->deposit(Money{c});
            std::cout << "Deposited " << format_money(Money{c}) << " to #" << id
                      << " (balance " << format_money(a->balance()) << ")\n";
        } else if (cmd == "withdraw") {
            int id; long long c; std::cin >> id >> c;
            Account* a{require(bank, id)};
            if (!a) continue;
            if (!a->withdraw(Money{c}))
                std::cout << "Insufficient funds for #" << id << " (balance " << format_money(a->balance()) << ")\n";
            else
                std::cout << "Withdrew " << format_money(Money{c}) << " from #" << id
                          << " (balance " << format_money(a->balance()) << ")\n";
        } else if (cmd == "transfer") {
            int from, to; long long c; std::cin >> from >> to >> c;
            Account* a{bank.find(from)}; Account* b{bank.find(to)};
            if (!a || !b) { std::cout << "Unknown account in transfer\n"; continue; }
            if (!a->withdraw(Money{c}, to, true)) {
                std::cout << "Insufficient funds for #" << from << " (balance " << format_money(a->balance()) << ")\n";
                continue;
            }
            b->deposit(Money{c}, from, true);
            std::cout << "Transferred " << format_money(Money{c}) << " #" << from << " -> #" << to << "\n";
        } else if (cmd == "history") {
            int id; std::cin >> id;
            Account* a{require(bank, id)};
            if (!a) continue;
            std::cout << "History for #" << a->id() << " " << a->name() << ":\n";
            for (int i{0}; i < a->tx_count(); ++i) {
                const Transaction& t{a->tx(i)};
                std::cout << "  " << tx_label(t.kind) << " " << format_money(t.amount);
                if (t.kind == TxKind::TransferIn || t.kind == TxKind::TransferOut)
                    std::cout << " (#" << t.other_id << ")";
                std::cout << "\n";
            }
        } else if (cmd == "summary") {
            std::cout << "Accounts: " << bank.count() << "\n";
            std::optional<Money> total{bank.total_assets()};
            std::cout << "Total assets: " << (total.has_value() ? format_money(*total) : std::string{"(no accounts)"}) << "\n";
        } else if (cmd == "quit") { break; }
    }
    return 0;
}
